var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"OVERFLOW_SCAVENGER_NULL_NULL","text":{"KOREA":"흐하하하하하!","JPN":"ふははははは！","ENG":"Mwa ha ha ha!","TWN":"哈哈哈哈哈哈！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"OVERFLOW_SCAVENGER_NULL_NULL","text":{"KOREA":"도망치는 재주가 제법이군! 본대에 끼지 못해서 아쉬웠는데 잘됐어!","JPN":"逃げるスキルは抜群だな！　本隊について行けなくて残念だったが、かえってよかったのかもな！","ENG":"You're slippery, I'll give you that! I was disappointed to be left out of the main forces, but this should make up for it!","TWN":"蠻會逃的嘛！本來我還因為沒能加入主隊而可惜呢，現在正好！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"젠장, 어쩐다. 총알이 다 떨어졌어.","JPN":"くそ、どうしよう。弾切れだ。","ENG":"Damn it. I'm out of ammo.","TWN":"可惡。子彈用完了。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L7_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그러게 단발로 쏘라니까요!","JPN":"だから、単発にしてって言ったのに！","ENG":"I told you to use single-fire mode!","TWN":"就叫你換成單發模式！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L8_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"내가 총 쏘면서 느끼는 체질인 줄 아냐? 삼점사라도 단발로는 흠집도 못 내니까 그렇지!","JPN":"私は銃を撃ちながら感じちゃう体質じゃないんだよ！　三点バーストでも単発じゃ傷一つ付けられないだろ！","ENG":"You think I get off on shooting recklessly? It's because even burst mode can't make a dent in him!","TWN":"誰開槍的時候還會在意這些啦？而且就算是三連發也傷不到他吧！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L9_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"못 살아! 지시에 안 따르는데 포지션이 무슨 의미냐구요!","JPN":"もうイヤ！　指示に従わないのに、ポジションに何の意味があるっていうのよ！","ENG":"You're driving me crazy! What good does positioning do if you won't follow instructions?!","TWN":"氣死我！如果不能聽從指示，那幹嘛要定位各自的角色！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L10_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"나도 못 살겠다! 태어나서 하는 일마다 꼬여 갖고!","JPN":"こっちこそやってらんないね！　生まれてこのかた何をやってもうまくいかないし！","ENG":"\\nI'm the one going crazy! Everything I've done since birth always gets messy!","TWN":"我才是咧！人生不如意的事十之八九啦！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"어른이면 자기 선택에 책임을 질 줄 알아야죠!","JPN":"大人だったら、自分の選択に責任を持つべきでしょ！","ENG":"As an adult, you should be responsible for your choices!","TWN":"大人就該為自己的選擇負責！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"불평할 시간에 어떻게 하면 저 작자들을 따돌릴 수 있을지나 생각해내요!","JPN":"文句言う暇があったら、どうやったらあいつらをまけるか考えてよ！","ENG":"If you have time to complain, why don't you use that time to think of a way to get them off of our tail?","TWN":"你有時間抱怨，還不如想想怎樣才能甩掉他們！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"젠장, 관리국은 꼭 이럴 때 늦장이지!","JPN":"くそ、管理局はこんなときに限って遅くなりやがる！","ENG":"Damn it, the Administration always picks the best time to be late!","TWN":"可惡，管理局每次都挑這種時候遲到！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L14_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"달려! 저쪽 건물로 넘어간다!","JPN":"走れ！　あっちの建物に渡る！","ENG":"Run! We're jumping over to that building!","TWN":"快跑！跳到那棟樓上去！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"거리가 너무 멀잖아요! 이 높이에서 떨어지면 사망이라구요!","JPN":"距離が遠すぎるわ！　この高さから落ちたら死亡確定よ！","ENG":"That's too far! We're going to die if we fall from this height!","TWN":"距離太遠了！這個高度掉下去會摔死的！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"옥상이 아니야! 창문으로 뛰어!","JPN":"屋上じゃない！　窓に飛び込め！","ENG":"Not the roof! Jump towards the window!","TWN":"不是樓頂！是往窗戶那跳！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"미쳤어…! 유리에 찔려 죽는다는 생각은 안 해요?!","JPN":"正気……！？　ガラスが刺さって死ぬことだってあるのよ！？","ENG":"You're insane...! The glass shards are going to stab us to death!","TWN":"神經病……！你不覺得會被碎玻璃扎死嗎？！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"방패는 뒀다가 어디다 쓰게!","JPN":"盾あるだろ！","ENG":"What do you think your shield is for?!","TWN":"你不是還拿著盾牌嗎！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"어차피 저것들에게 끌려가면 평생 노예 신세야! 차라리 죽는 편이 낫지!","JPN":"どうせあいつらに捕まれば一生奴隷なんだ！　それよりかはいっそ死んだ方がマシだろ！","ENG":"Besides, if we get caught by them, we're gonna be their slaves forever! I'd rather die!","TWN":"反正被他們逮到的話也要當一輩子奴隸！那還不如去死！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"간다!!","JPN":"行くぞ！！","ENG":"Let's go!!","TWN":"快跳！！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L29_1","type":"dialog","speaker":"GLITCH_SCAVENGER_NULL_NULL","text":{"KOREA":"오, 맙소사. 제 발로 막다른 골목에 들어가 버렸네.","JPN":"おやおや。飛んで火に入る何とやら。","ENG":"Oh, dear. They've walked into a corner all by themselves.","TWN":"噢！呃……呃。她們把自己逼到絕境咧？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"GLITCH_SCAVENGER_NULL_NULL","text":{"KOREA":"불이라도 지를까? 따끈따끈하게 만들어서 제 발로 나오게?","JPN":"火でもつけちゃうか？　アツアツにして、自分の足で出てくるようにさ。","ENG":"Should we start a fire? Make it so hot that they can't help but come out?","TWN":"不如放把火吧？燒到她們自己走出來？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"OVERFLOW_SCAVENGER_NULL_NULL","text":{"KOREA":"……아니. 추격은 끝이다. 복귀하자.","JPN":"……いや。追撃は終わりだ。復帰しよう。","ENG":"...No. The chase ends here. We're going back.","TWN":"……不用，追擊結束，回去吧。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"GLITCH_SCAVENGER_NULL_NULL","text":{"KOREA":"에엥? 왜? 왜? 왜왜왜?","JPN":"ええっ？　なんで？　なんで？　なんでなんでなんで？","ENG":"Huuuh? But why? Why? Whywhywhy?","TWN":"蛤？為什麼？為什麼？為什麼？到底是為什麼？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"OVERFLOW_SCAVENGER_NULL_NULL","text":{"KOREA":"<color=#ffd34c>저긴</color> 두목이 건드리지 말라고 한 곳이다.","JPN":"<color=#ffd34c>あそこ</color>はボスが手を出すなって言ったところだぞ。","ENG":"Boss ordered us not to mess with <color=#ffd34c>that place</color>.","TWN":"<color=#ffd34c>那棟樓</color>，老大說過不准碰。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"OVERFLOW_SCAVENGER_NULL_NULL","text":{"KOREA":"건드리려면 두목부터 이기고 오시지.","JPN":"手を出したけりゃ、ボスを倒してこい。","ENG":"Or you can do that after you beat Boss.","TWN":"想碰的話，等你打贏老大再說。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"GLITCH_SCAVENGER_NULL_NULL","text":{"KOREA":"아…. 저런. 아깝게 됐네.","JPN":"あ……あちゃ。残念だな。","ENG":"Ah... Well, that's a shame.","TWN":"嘖……哎呀，真可惜。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"GLITCH_SCAVENGER_NULL_NULL","text":{"KOREA":"술래잡기 재밌었어, 아가씨들! 다음에 또 놀자고! 흐히히힉!","JPN":"かくれんぼ楽しかったぜ、レディーたち！　また遊ぼうぜ！　ふへへへへっ！","ENG":"I enjoyed playing tag with you, ladies! Let's do this again sometime! Hee hee hee hek!","TWN":"捉迷藏很好玩。小姐們！下次再一起玩吧！咦嘻嘻嘻！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L42_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"으윽…. 으……. 저 자식들, 포기한 건가?","JPN":"ううっ……うう……あいつら、あきらめたのか？","ENG":"Kgh... Ugh... Did they stop chasing us?","TWN":"呼……呼呼……他們，放棄了嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L43_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"꼬맹이, 살아 있냐?","JPN":"おこちゃま、生きてる？","ENG":"You alive, kid?","TWN":"喂，小鬼，你還活著嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"말 시키지 마요…. 온몸이 누구한테 두들겨 맞은 것 같아….","JPN":"話しかけないで……誰かに全身ボコボコにされたような気分なの……","ENG":"Don't talk to me... Every part of my body's aching right now...","TWN":"別跟我說話……我全身都痛，好像被卡車撞到一樣……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"하아……. 그래, 그냥 누워서 들어라.","JPN":"はあ……あっそ、じゃあ転がったまま聞きな。","ENG":"*Sigh*... Fine, then just listen while lying down.","TWN":"哈……好吧，那你躺著聽我說吧。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L46_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"여기 어때? 쓸 만하지 않을까?","JPN":"ここ、どう？　使えそうじゃないか？","ENG":"What do you think about this place? Looks pretty decent, right?","TWN":"你覺得這裡怎麼樣？應該能用吧？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"말 시키지 말라니까요……. 그냥 평범하게 안 쓰는 사무실이잖아요.","JPN":"話しかけないでったら……ただの使ってない事務所じゃない。","ENG":"I told you not to talk to me... It's just an empty, ordinary office.","TWN":"就叫你別跟我說話……不就是一間閒置的普通辦公室嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그래서 하는 말이야.","JPN":"だから聞いてるんだよ。","ENG":"Exactly.","TWN":"所以說！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"주인 없는 사무실이면, 며칠 지내도 누가 뭐라고 하진 않겠지.","JPN":"主のいない事務所なら、数日泊まっても誰も怒らないだろ？","ENG":"It's an unoccupied office. No one's going to say anything if we were to stay here for a couple of days.","TWN":"如果是沒人的辦公室，我們待幾天也不會有人說什麼吧？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"천재다.","JPN":"天才だ。","ENG":"That's genius.","TWN":"你真是個天才。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};